// Solution
class Calculator<T> {
  private static isNumber<T>(value: T): value is number {
    return typeof value === 'number';
  }

  public calculate<T, U>(a: T, b: U): T & U {
    if (Calculator.isNumber(a) && Calculator.isNumber(b)) {
      return a + b;
    } else if (typeof a === 'string' && typeof b === 'string') {
      return a + b;
    } else if (typeof a === 'boolean' && typeof b === 'boolean') {
      return a && b;
    } else if (Calculator.isNumber(a) && typeof b === 'string') {
      return a + b;
    } else if (typeof a === 'string' && Calculator.isNumber(b)) {
      return a + b;
    } else if (Calculator.isNumber(a) && Calculator.isNumber(b)) {
      if (b === 0) {
        return NaN;
      } else {
        return a / b;
      }
    } else {
      return NaN;
    }
  }
}

